import{_ as r,a as e,b as t,c as p,d as i,e as o,f as _,g as s,h as l}from"./chunks/9.C3OArozJ.js";import{_ as h,o as n,c as d,ag as c}from"./chunks/framework.ETe_P6d1.js";const m="/kaiping-reports/assets/10.Bp-dU8Ku.jpg",S=JSON.parse('{"title":"开平碉楼遗产语境下的场所重构研究——以赤坎古镇为切入的空间、建造与活化策略分析","description":"","frontmatter":{"title":"开平碉楼遗产语境下的场所重构研究——以赤坎古镇为切入的空间、建造与活化策略分析"},"headers":[],"relativePath":"reports/罗梓瑄/罗梓瑄_开平碉楼遗产语境下的场所重构研究——以赤坎古镇为切入的空间、建造与活化策略分.md","filePath":"reports/罗梓瑄/罗梓瑄_开平碉楼遗产语境下的场所重构研究——以赤坎古镇为切入的空间、建造与活化策略分.md"}'),u={name:"reports/罗梓瑄/罗梓瑄_开平碉楼遗产语境下的场所重构研究——以赤坎古镇为切入的空间、建造与活化策略分.md"};function b(q,a,f,P,k,x){return n(),d("div",null,[...a[0]||(a[0]=[c('<h1 id="开平碉楼遗产语境下的场所重构研究——以赤坎古镇为切入的空间、建造与活化策略分析" tabindex="-1">开平碉楼遗产语境下的场所重构研究——以赤坎古镇为切入的空间、建造与活化策略分析 <a class="header-anchor" href="#开平碉楼遗产语境下的场所重构研究——以赤坎古镇为切入的空间、建造与活化策略分析" aria-label="Permalink to &quot;开平碉楼遗产语境下的场所重构研究——以赤坎古镇为切入的空间、建造与活化策略分析&quot;">​</a></h1><h1 id="作者-罗梓瑄" tabindex="-1">作者：罗梓瑄 <a class="header-anchor" href="#作者-罗梓瑄" aria-label="Permalink to &quot;作者：罗梓瑄&quot;">​</a></h1><h1 id="一、引言-从-防御建筑-对-文化景观-的转型" tabindex="-1">一、引言：从“防御建筑”对“文化景观”的转型 <a class="header-anchor" href="#一、引言-从-防御建筑-对-文化景观-的转型" aria-label="Permalink to &quot;一、引言：从“防御建筑”对“文化景观”的转型&quot;">​</a></h1><p><img src="'+r+'" alt="图1"></p><p>开平碉楼作为近代华侨社会的重要物质遗存，是多重历史力量交织的结果。其形成既源于岭南地区的社会动荡与防御需求，也深受海外文化回流的影响。2007年，“开平碉楼与村落”被列入世界文化遗产名录，标志着其从地方性居住与防御设施，转化为具有全球价值的文化遗产。</p><p>在众多遗产点中，赤坎古镇呈现出一种不同于传统村落的复杂性：它既是商业墟市，又是侨乡文化的展示窗口，更是在当代被整体改造为文化旅游目的地。因此，赤坎不仅是“建筑遗产”，更是一个被重新生产的“文化场所”。</p><p>本报告以赤坎古镇为核心，结合开平碉楼整体语境，从空间类型、建造逻辑、文化表达及当代改造等八个维度展开分析，探讨在遗产转型过程中，建筑语言如何被重构，以及场所精神如何跟随时代被重新定义。</p><h1 id="二、空间类型与形态-从墟市肌理到旅游空间" tabindex="-1">二、空间类型与形态：从墟市肌理到旅游空间 <a class="header-anchor" href="#二、空间类型与形态-从墟市肌理到旅游空间" aria-label="Permalink to &quot;二、空间类型与形态：从墟市肌理到旅游空间&quot;">​</a></h1><p>赤坎古镇的空间结构以骑楼街为骨架，沿潭江两岸展开，呈现出典型的线性商业聚落特征。</p><p>赤坎古镇的建筑类型主要包括：骑楼式商铺（主导类型）、后宅式民居、仓储建筑、少量碉楼与防御性建筑。其中，骑楼建筑是最具代表性的空间单元，其连续性构成了完整的街道界面。</p><p>在平面布局与空间层级上，典型骑楼建筑呈“前店后宅”模式：前部为开敞式商铺，中部为过渡厅堂，后部为居住或仓储空间。空间序列为街道 → 骑楼廊道 → 店铺 → 内院/后宅。</p><p>这一序列体现出从公共到私密的渐进关系，但在当代改造后，这一层级被明显弱化，为了实现商业发展，很多原本的隔断空间被打通，商业空间全面前置，原有的空间秩序消失。</p><p>在空间形态特征上连续柱廊形成灰空间系统，建筑高度多为2–4层，形成稳定街道界面，街宽与建筑高度比例适中（约1:1至1:1.5），空间具有良好围合感。改造后，空间被进一步“景观化”，街道成为游客流动的主要载体，而非原有的社区生活空间。</p><p><img src="'+e+'" alt="图2"></p><h1 id="三、建造材料与构造-传统工艺与工业技术的叠合" tabindex="-1">三、建造材料与构造：传统工艺与工业技术的叠合 <a class="header-anchor" href="#三、建造材料与构造-传统工艺与工业技术的叠合" aria-label="Permalink to &quot;三、建造材料与构造：传统工艺与工业技术的叠合&quot;">​</a></h1><p><img src="'+t+'" alt="图3"></p><p>在结构体系上，赤坎古镇建筑多采用砖混结构（早期）、钢筋混凝土结构（后期改造）。部分骑楼在改造中进行了结构加固，加入隐蔽钢结构体系。在材料表达上外墙多用抹灰、水刷石、局部红砖。楼板用混凝土现浇或预制板。屋顶则为传统坡屋顶与平屋顶并存。</p><p>改造后，大量建筑表面被统一修复，呈现出“新旧一致”的视觉效果，但削弱了原有材料的时间层次。</p><p>从构造方式上，原有建筑以手工砌筑为主，但改造部分为现代施工技术（现浇、预制）。施工痕迹在改造中被“抹平”，使建筑更趋于“展览性”而非“历史性”。</p><p><img src="'+p+'" alt="图4"></p><h1 id="四、装饰符号与文化表达-从真实记忆到视觉符号" tabindex="-1">四、装饰符号与文化表达：从真实记忆到视觉符号 <a class="header-anchor" href="#四、装饰符号与文化表达-从真实记忆到视觉符号" aria-label="Permalink to &quot;四、装饰符号与文化表达：从真实记忆到视觉符号&quot;">​</a></h1><p>一是中西融合特征。赤坎骑楼体现典型的华侨建筑混合语言例如西式拱券 + 中式屋顶、几何装饰 + 灰塑题材。</p><p>二是装饰题材上用几何纹样、花卉与动物图案、商号文字与招牌进行装饰。改造后，这些元素被强化、修复甚至重绘，成为“文化符号”的展示对象，而有些店铺为了广告或宣传作用，也会滥用一些与古镇并不符合的元素。</p><p><img src="'+i+'" alt="图5"><img src="'+o+'" alt="图6"></p><p>三是色彩体系上，原始的为灰、白、红砖色为主。改造后色彩更统一、对比更强。这种处理增强了视觉吸引力，但也带来“过度修复”的争议。</p><h1 id="五、功能布局与使用方式-从生活空间到消费空间" tabindex="-1">五、功能布局与使用方式：从生活空间到消费空间 <a class="header-anchor" href="#五、功能布局与使用方式-从生活空间到消费空间" aria-label="Permalink to &quot;五、功能布局与使用方式：从生活空间到消费空间&quot;">​</a></h1><p>古镇的原始功能主要是商业交易和居住生活。在当代赤坎古镇已转变为民宿、餐饮空间、文创商店、展览与表演空间为一体的综合性大型旅游地。</p><p><img src="'+_+'" alt="图7"></p><p>从前的流线组织，以居民日常流线为导向，而现在则以游客的观光流线为导向。动线被重新设计为入口 → 主街 → 节点广场 → 主题空间 → 出口。建筑不再服务“居住者”，而是服务“参观者”。</p><p><img src="'+s+'" alt="图8"></p><h1 id="六、环境关系与场所精神-从水乡聚落到景观叙事" tabindex="-1">六、环境关系与场所精神：从水乡聚落到景观叙事 <a class="header-anchor" href="#六、环境关系与场所精神-从水乡聚落到景观叙事" aria-label="Permalink to &quot;六、环境关系与场所精神：从水乡聚落到景观叙事&quot;">​</a></h1><p>原建筑与自然环境关系是赤坎依托潭江形成则临水布局，同时在古镇上形成了具有特色的水陆交通体系。</p><p><img src="'+l+'" alt="图9"></p><p>而原本村落的肌理是自发生长的、功能驱动的。改造后则以规划控制、景观导向为主要的目标。</p><p>从人的视线与景观上来看，原本人们以生活视角去看待村落（看河、看街）。而现在则是游客以观光视角（打卡、摄影）。场所精神从“生活空间”转变为“展示空间”。</p><h1 id="七、尺度与人体感知-从日常尺度到旅游尺度" tabindex="-1">七、尺度与人体感知：从日常尺度到旅游尺度 <a class="header-anchor" href="#七、尺度与人体感知-从日常尺度到旅游尺度" aria-label="Permalink to &quot;七、尺度与人体感知：从日常尺度到旅游尺度&quot;">​</a></h1><p>建筑尺度多为高度2–4层的骑楼。空间体验上，原本的村是亲切、日常、可停留的。改造后则流动性增强、停留减少。院落空间被弱化，街道成为主要体验空间。</p><h1 id="八、现代改造与适应性更新-整体开发的双刃剑" tabindex="-1">八、现代改造与适应性更新：整体开发的双刃剑 <a class="header-anchor" href="#八、现代改造与适应性更新-整体开发的双刃剑" aria-label="Permalink to &quot;八、现代改造与适应性更新：整体开发的双刃剑&quot;">​</a></h1><p>赤坎采用“整体性开发”策略，主要表现为居民迁出、建筑统一修复、功能整体置换。在新旧关系上，新材料大量介入，旧建筑被“更新为新”，形成一种“仿旧”的视觉统一。</p><p>对于满足旅游功能植入方式，强商业导入，文化活动嵌入，旅游服务设施完善，以及与古镇原本文化背景所契合的特色表演。这种模式在经济上成功，但文化真实性受到挑战。</p><h1 id="九、问题与可能性-遗产再生的批判性思考" tabindex="-1">九、问题与可能性：遗产再生的批判性思考 <a class="header-anchor" href="#九、问题与可能性-遗产再生的批判性思考" aria-label="Permalink to &quot;九、问题与可能性：遗产再生的批判性思考&quot;">​</a></h1><p>现存问题有，原真性削弱、建筑被过度修复，历史痕迹消失。社区缺失、居民迁出，场所失去生活基础。商业同质化、商铺类型趋同，文化表达单一。</p><p>在我与同学的讨论下我认为赤坎古镇可以从以下几点进行改造，例如，引入部分原住民回归（效仿乌镇聘用当地原住民）。保留未修复区域作为“时间样本”，强化非物质文化展示。</p><p>赤坎古镇给我提供了重要启示，一是遗产保护不应仅关注“形式”、二是场所精神来源于“使用”而非“展示”、三是建筑语言应服务真实生活，而非仅作为视觉符号。</p><h1 id="十、结论-在-再造-与-真实-之间寻找平衡" tabindex="-1">十、结论：在“再造”与“真实”之间寻找平衡 <a class="header-anchor" href="#十、结论-在-再造-与-真实-之间寻找平衡" aria-label="Permalink to &quot;十、结论：在“再造”与“真实”之间寻找平衡&quot;">​</a></h1><p><img src="'+m+'" alt="图10"></p><p>赤坎古镇的实践代表了一种极端但具有代表性的遗产活化路径——通过整体改造实现文化旅游开发。这种模式在短期内实现了经济价值最大化，但也引发了关于真实性、社区权利与文化深度的广泛讨论。</p><p>相比之下，开平碉楼整体体系中的不同案例（如立园、仓东村）提示我们，遗产保护不存在单一答案，而应基于类型差异采取多元策略。</p><p>未来的方向不应是简单复制赤坎模式，而应在保护中保留不完美，在更新中引入真实生活，在展示中保持文化深度。唯有如此，开平碉楼才能从“被观看的遗产”，转变为“被生活的遗产”。</p><h1 id="十一、参考书目" tabindex="-1">十一、参考书目 <a class="header-anchor" href="#十一、参考书目" aria-label="Permalink to &quot;十一、参考书目&quot;">​</a></h1><p>广东省文物考古研究所：《开平碉楼》，文物出版社，2007 华侨大学建筑学院：《华侨建筑文化研究》，中国建筑工业出版社，2010 同济大学建筑与城市规划学院：《文化遗产保护的理论与实践》，同济大学出版社，2015 华南理工大学出版社：《开平碉楼村落保护与利用研究》，2018 陈志华：《乡土建筑的价值与保护》，中国建筑工业出版社，2006 张松：《历史城市保护学导论》，同济大学出版社，2013</p>',51)])])}const $=h(u,[["render",b]]);export{S as __pageData,$ as default};
